def test_validate_assignment_extra_forbid():
    @pydantic.dataclasses.dataclass(config=ConfigDict(validate_assignment=True, extra=Extra.forbid))
    class MyDataclass:
        a: int

    d = MyDataclass(1)
    assert d.a == 1

    with pytest.raises(ValidationError) as exc_info:
